import{_ as t,o as a,c as n,a2 as i}from"./chunks/framework.B72_uj9U.js";const p=JSON.parse('{"title":"Linear Tutorial Track","description":"Understand the theory behind coding agents, then implement each component","frontmatter":{"title":"Linear Tutorial Track","description":"Understand the theory behind coding agents, then implement each component"},"headers":[],"relativePath":"learn/linear/index.md","filePath":"learn/linear/index.md"}'),r={name:"learn/linear/index.md"};function o(l,e,d,s,c,h){return a(),n("div",null,[...e[0]||(e[0]=[i('<h1 id="linear-tutorial-track" tabindex="-1">Linear Tutorial Track <a class="header-anchor" href="#linear-tutorial-track" aria-label="Permalink to &quot;Linear Tutorial Track&quot;">​</a></h1><p>A concept-first approach to building CLI coding agents. Each chapter explores a key topic in depth — the theory, the trade-offs, and the implementation patterns — before you write code.</p><p>This track is ideal if you want to understand <em>why</em> things work the way they do. You&#39;ll study real-world agents (Claude Code, OpenCode, Pi), learn the underlying concepts, and then implement each component with a deep understanding.</p><h2 id="learning-objectives" tabindex="-1">Learning Objectives <a class="header-anchor" href="#learning-objectives" aria-label="Permalink to &quot;Learning Objectives&quot;">​</a></h2><ul><li>Understand the architecture and design patterns of modern coding agents</li><li>Learn Rust from a Python developer&#39;s perspective</li><li>Master each component: LLM APIs, tool systems, TUI, streaming, and more</li><li>Study real-world implementations and extract common patterns</li><li>Build a coding agent grounded in solid theoretical understanding</li></ul><h2 id="chapters" tabindex="-1">Chapters <a class="header-anchor" href="#chapters" aria-label="Permalink to &quot;Chapters&quot;">​</a></h2><ol><li><a href="/linear/01-what-is-a-coding-agent/">What Is a Coding Agent?</a> — The AI coding revolution</li><li><a href="/linear/02-rust-for-python-developers/">Rust for Python Developers</a> — Bridging the language gap</li><li><a href="/linear/03-understanding-llms/">Understanding LLMs</a> — How language models work for agents</li><li><a href="/linear/04-anatomy-of-an-agentic-loop/">Anatomy of an Agentic Loop</a> — The core pattern</li><li><a href="/linear/05-tool-systems-deep-dive/">Tool Systems Deep Dive</a> — How agents interact with the world</li><li><a href="/linear/06-file-system-operations/">File System Operations</a> — Reading, writing, and editing code</li><li><a href="/linear/07-process-management-and-shell/">Process Management and Shell</a> — Running commands safely</li><li><a href="/linear/08-streaming-and-realtime/">Streaming and Realtime</a> — Server-sent events and incremental rendering</li><li><a href="/linear/09-terminal-user-interfaces/">Terminal User Interfaces</a> — Building beautiful TUIs</li><li><a href="/linear/10-conversation-state-machines/">Conversation State Machines</a> — Managing context and history</li><li><a href="/linear/11-code-intelligence/">Code Intelligence</a> — Tree-sitter, grep, and semantic search</li><li><a href="/linear/12-version-control-integration/">Version Control Integration</a> — Git as infrastructure</li><li><a href="/linear/13-safety-and-permissions/">Safety and Permissions</a> — Threat models and guardrails</li><li><a href="/linear/14-provider-abstraction/">Provider Abstraction</a> — Supporting multiple LLM providers</li><li><a href="/linear/15-extensibility-patterns/">Extensibility Patterns</a> — Plugins, MCP, and hooks</li><li><a href="/linear/16-testing-coding-agents/">Testing Coding Agents</a> — How to test non-deterministic systems</li><li><a href="/linear/17-packaging-and-distribution/">Packaging and Distribution</a> — Shipping Rust binaries</li><li><a href="/linear/18-case-study-building-it-all/">Case Study: Building It All</a> — Putting it all together</li></ol><h2 id="cross-reference-project-track" tabindex="-1">Cross-Reference: Project Track <a class="header-anchor" href="#cross-reference-project-track" aria-label="Permalink to &quot;Cross-Reference: Project Track&quot;">​</a></h2><p>Each linear chapter has a corresponding project track chapter where you implement the same concepts hands-on.</p><table tabindex="0"><thead><tr><th>Linear Chapter</th><th>Project Chapter</th></tr></thead><tbody><tr><td>1. What Is a Coding Agent?</td><td>— (conceptual overview)</td></tr><tr><td>2. Rust for Python Developers</td><td>1. Hello, Rust CLI</td></tr><tr><td>3. Understanding LLMs</td><td>2. First LLM Call</td></tr><tr><td>4. Anatomy of an Agentic Loop</td><td>3. The Agentic Loop</td></tr><tr><td>5. Tool Systems Deep Dive</td><td>4. Building a Tool System</td></tr><tr><td>6. File System Operations</td><td>5. File Operations Tools</td></tr><tr><td>7. Process Management and Shell</td><td>6. Shell Execution</td></tr><tr><td>8. Streaming and Realtime</td><td>7. Streaming Responses</td></tr><tr><td>9. Terminal User Interfaces</td><td>8. Terminal UI with Ratatui</td></tr><tr><td>10. Conversation State Machines</td><td>9. Conversation Context Management</td></tr><tr><td>11. Code Intelligence</td><td>10. Search and Code Intelligence</td></tr><tr><td>12. Version Control Integration</td><td>11. Git Integration</td></tr><tr><td>13. Safety and Permissions</td><td>12. Permission and Safety</td></tr><tr><td>14. Provider Abstraction</td><td>13. Multi-Provider Support</td></tr><tr><td>15. Extensibility Patterns</td><td>14. Extensibility and Plugins</td></tr><tr><td>16. Testing Coding Agents</td><td>15. Production Polish</td></tr><tr><td>17. Packaging and Distribution</td><td>15. Production Polish</td></tr><tr><td>18. Case Study: Building It All</td><td>— (capstone)</td></tr></tbody></table><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li>Basic programming experience (Python is perfect)</li><li>Willingness to think before coding</li><li>Interest in understanding how AI tools work under the hood</li></ul>',12)])])}const u=t(r,[["render",o]]);export{p as __pageData,u as default};
